import{_ as a,o as t,c as s,a5 as o}from"./chunks/framework.COADHF96.js";const p=JSON.parse('{"title":"Skills","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills.md","filePath":"guide/skills.md","lastUpdated":1781779105000}'),i={name:"guide/skills.md"};function l(n,e,r,d,c,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h1><p><strong>Skills</strong> are ready-to-use, drop-in bundles of prompts and instructions that teach an AI agent how to do a specific creative job with Picsart&#39;s models. Download a skill, hand it to <strong>Claude Code, Cursor, Windsurf, or ChatGPT</strong>, and the agent already knows which model to pick, how to structure the prompt, and which <code>gen-ai</code> command to run — you just ask in plain English.</p><blockquote><p>Official page: <a href="https://picsart.com/gen-ai-skills/" target="_blank" rel="noreferrer">picsart.com/gen-ai-skills</a></p></blockquote><h2 id="how-skills-relate-to-the-cli-and-mcp" tabindex="-1">How skills relate to the CLI and MCP <a class="header-anchor" href="#how-skills-relate-to-the-cli-and-mcp" aria-label="Permalink to &quot;How skills relate to the CLI and MCP&quot;">​</a></h2><p>A skill is the <strong>knowledge layer</strong>; the <a href="/picsart-mcp-cli-docs/guide/cli-quickstart">gen-ai CLI</a> is the <strong>engine</strong>. Skills drive the CLI under the hood, and the whole thing speaks <a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP</a> so it works natively inside agents. So the setup order is:</p><ol><li><strong>Install the CLI</strong> — see <a href="/picsart-mcp-cli-docs/guide/installation">Installation</a>.</li><li><strong>Authenticate</strong> — <code>gen-ai login</code> (once per machine).</li><li><strong>Add a skill</strong> to your agent (below).</li></ol><h2 id="the-gen-ai-use-skill" tabindex="-1">The <code>gen-ai-use</code> skill <a class="header-anchor" href="#the-gen-ai-use-skill" aria-label="Permalink to &quot;The `gen-ai-use` skill&quot;">​</a></h2><p>The flagship skill, <strong><code>gen-ai-use</code></strong>, gives an agent access to all <strong>130+ models</strong> across image, video, and audio generation. It works with Claude Code, Cursor, and Windsurf.</p><p>Once added, you drive it conversationally:</p><blockquote><p>&quot;Make me three banner concepts for the spring sale.&quot;</p><p>&quot;Turn these 10 product photos into a 9:16 reel with background music.&quot;</p><p>&quot;Generate hero images for this landing page in 16:9 and 1:1.&quot;</p></blockquote><p>The agent picks the right model, builds the prompt, runs the <code>gen-ai</code> command in the background, and hands back the results.</p><h2 id="installing-a-skill" tabindex="-1">Installing a skill <a class="header-anchor" href="#installing-a-skill" aria-label="Permalink to &quot;Installing a skill&quot;">​</a></h2><p>Skills ship as a single <code>.zip</code> bundle. Download it from <a href="https://picsart.com/gen-ai-skills/" target="_blank" rel="noreferrer">picsart.com/gen-ai-skills</a> and add it to your agent:</p><ul><li><strong>Claude Code</strong> — add the skill bundle to your skills directory, then invoke it (e.g. <code>/gen-ai-use</code>) or just describe the task.</li><li><strong>Cursor / Windsurf</strong> — drop the bundle in per the agent&#39;s skill/rules import, then ask in plain English.</li><li><strong>ChatGPT</strong> — attach the skill and prompt normally.</li></ul><p>Because skills call the CLI, make sure <code>gen-ai --version</code> works and you&#39;ve run <code>gen-ai login</code> first.</p><h2 id="what-skills-are-good-for" tabindex="-1">What skills are good for <a class="header-anchor" href="#what-skills-are-good-for" aria-label="Permalink to &quot;What skills are good for&quot;">​</a></h2><ul><li><strong>Hero images</strong> — on-brand key art in the aspect ratios you need.</li><li><strong>Reels &amp; shorts</strong> — chain stills into short social video with motion and audio.</li><li><strong>Batch catalogs</strong> — generate or edit assets across hundreds or thousands of SKUs.</li></ul><h2 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h2><p>For OpenAI Codex, install the CLI and add the curated plugin:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codex://plugins/picsart@openai-curated</span></span></code></pre></div><p>See <a href="/picsart-mcp-cli-docs/guide/installation#mcp-agent-integrations">Installation → MCP &amp; agent integrations</a> for all agent paths.</p>',21)])])}const u=a(i,[["render",l]]);export{p as __pageData,u as default};
